import { Transaction } from '@iota/iota-sdk/transactions';
// ==========================================
// Initialize IOTA Client
// ==========================================
const PACKAGE_ID = '0x3a43c05a17483b7c754a04439b5f83db473a4c6b18968a2a15b7718286bd81bc';
const MODULE = 'generic_store';

function moveTarget(fn: string): string {
  return `${PACKAGE_ID}::${MODULE}::${fn}`;
}

function submitTx(
  signAndExecuteTransaction: any,
  tx: Transaction,
  address: string,
  setDigest: (d: string) => void
) {
  tx.setSender(address);

  signAndExecuteTransaction(
    { transaction: tx },
    {
      onSuccess: (res: any) => {
        console.log('TX success', res);
        setDigest(res.digest);
      },
      onError: (err: any) => {
        console.error('TX failed', err);
      },
    }
  );
}
